#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
const int N=2010,NN=4e6+10,Mod=1e9+7;int fac[NN],ifac[NN];
inline int qpow(int a,int b=Mod-2){int r=1;for(;b;b>>=1,a=1ll*a*a%Mod)if(b&1)r=1ll*r*a%Mod;return r;}
inline void Init(int n=4e6)
{
	fac[0]=fac[1]=ifac[0]=ifac[1]=1;rep(2,n,i)fac[i]=1ll*fac[i-1]*i%Mod;
	ifac[n]=qpow(fac[n]);drep(n,3,i)ifac[i-1]=1ll*ifac[i]*i%Mod;
}
inline int C(int n,int m){return 1ll*fac[n]*ifac[n-m]%Mod*ifac[m]%Mod;}
int dp[N][N],n,k;
int main()
{
	scanf("%d%d",&n,&k);
	if(k==1)return puts("1"),0;
	Init(n*k);rep(1,n,i)
	{
		dp[i][0]=1;rep(1,i,j)
		{
			dp[i][j]=(1ll*dp[i][j-1]*C(n*k-i-1-(j-1)*(k-1),k-2)%Mod*(n-j+1)+dp[i-1][j])%Mod;
		}
	}
	printf("%d\n",dp[n][n]);
}
